import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getResumes, uploadResume, deleteResume, searchResumes } from '../services/api';

function ScoreBadge({ score }) {
  const color = score >= 70 ? '#10b981' : score >= 40 ? '#f59e0b' : '#ef4444';
  const bg = score >= 70 ? '#d1fae5' : score >= 40 ? '#fef3c7' : '#fee2e2';
  return (
    <div style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 56, height: 56, borderRadius: '50%', border: `3px solid ${color}`, background: bg, color, fontWeight: 700, fontSize: 14, flexShrink: 0 }}>
      {score}%
    </div>
  );
}

export default function Resumes() {
  const { jobId } = useParams();
  const [resumes, setResumes] = useState([]);
  const [files, setFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState({ done: 0, total: 0 });
  const [search, setSearch] = useState('');
  const [show, setShow] = useState(false);
  const [filter, setFilter] = useState('all');

  const load = () => getResumes(jobId).then(r => setResumes(r.data));
  useEffect(() => { load(); }, [jobId]);

  // Auto-extract name and email from filename or use index
  const handleFilesChange = (e) => {
    const selected = Array.from(e.target.files);
    setFiles(selected.map((f, i) => ({
      file: f,
      candidateName: f.name.replace('.pdf', '').replace(/_/g, ' ').replace(/-/g, ' '),
      email: `candidate${i + 1}@upload.com`
    })));
  };

  const handleUploadAll = async () => {
    if (files.length === 0) return;
    setUploading(true);
    setProgress({ done: 0, total: files.length });

    for (let i = 0; i < files.length; i++) {
      const item = files[i];
      const fd = new FormData();
      fd.append('file', item.file);
      fd.append('jobId', jobId);
      fd.append('candidateName', item.candidateName);
      fd.append('email', item.email);
      try { await uploadResume(fd); } catch (e) { console.error(e); }
      setProgress({ done: i + 1, total: files.length });
    }

    setFiles([]);
    setShow(false);
    setUploading(false);
    load();
  };

  const handleSearch = async () => {
    if (!search.trim()) { load(); return; }
    const r = await searchResumes(search);
    setResumes(r.data);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete resume?')) { await deleteResume(id); load(); }
  };

  const filtered = resumes.filter(r => {
    if (filter === 'top') return r.atsScore >= 70;
    if (filter === 'mid') return r.atsScore >= 40 && r.atsScore < 70;
    if (filter === 'low') return r.atsScore < 40;
    return true;
  });

  const top3 = [...resumes].slice(0, 3);

  return (
    <div className="page">
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
        <h2>Candidates ({resumes.length})</h2>
        <button className="btn-primary" onClick={() => setShow(!show)}>{show ? 'Cancel' : '+ Upload Resumes'}</button>
      </div>

      {/* BULK UPLOAD PANEL */}
      {show && (
        <div className="card" style={{ marginBottom: 24 }}>
          <h2>Bulk Upload Resumes (PDF)</h2>
          <p style={{ color: '#666', fontSize: 13, marginBottom: 12 }}>Select multiple PDF files at once — all will be analyzed automatically.</p>

          <input type="file" accept=".pdf" multiple onChange={handleFilesChange}
            style={{ marginBottom: 12 }} />

          {files.length > 0 && (
            <div style={{ marginBottom: 14 }}>
              <div style={{ fontWeight: 600, marginBottom: 8 }}>Selected {files.length} file(s) — edit names if needed:</div>
              <div style={{ maxHeight: 200, overflowY: 'auto', border: '1px solid #eee', borderRadius: 6 }}>
                {files.map((f, i) => (
                  <div key={i} style={{ display: 'flex', gap: 10, padding: '8px 12px', borderBottom: '1px solid #f0f0f0', alignItems: 'center' }}>
                    <span style={{ fontSize: 12, color: '#888', width: 24 }}>{i + 1}.</span>
                    <span style={{ fontSize: 12, color: '#555', width: 160, flexShrink: 0 }}>{f.file.name}</span>
                    <input value={f.candidateName} placeholder="Candidate Name"
                      onChange={e => { const arr = [...files]; arr[i].candidateName = e.target.value; setFiles(arr); }}
                      style={{ flex: 1, padding: '5px 8px', fontSize: 13 }} />
                    <input value={f.email} placeholder="Email"
                      onChange={e => { const arr = [...files]; arr[i].email = e.target.value; setFiles(arr); }}
                      style={{ flex: 1, padding: '5px 8px', fontSize: 13 }} />
                  </div>
                ))}
              </div>
            </div>
          )}

          {uploading && (
            <div style={{ marginBottom: 12 }}>
              <div style={{ fontSize: 13, marginBottom: 6, color: '#4f46e5' }}>
                Processing {progress.done} of {progress.total}...
              </div>
              <div style={{ background: '#e5e7eb', borderRadius: 10, height: 10 }}>
                <div style={{ background: '#4f46e5', height: 10, borderRadius: 10, width: `${(progress.done / progress.total) * 100}%`, transition: 'width 0.3s' }} />
              </div>
            </div>
          )}

          <button className="btn-success" onClick={handleUploadAll} disabled={uploading || files.length === 0}>
            {uploading ? `Analyzing... (${progress.done}/${progress.total})` : `Upload & Analyze All (${files.length})`}
          </button>
        </div>
      )}

      {/* TOP 3 BANNER */}
      {resumes.length >= 2 && (
        <div className="card" style={{ marginBottom: 20, background: 'linear-gradient(135deg, #ede9fe, #dbeafe)' }}>
          <div style={{ fontWeight: 700, marginBottom: 12, fontSize: 15 }}>🏆 Top Candidates</div>
          <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap' }}>
            {top3.map((r, i) => (
              <div key={r.id} style={{ background: '#fff', borderRadius: 8, padding: '10px 16px', display: 'flex', alignItems: 'center', gap: 10, minWidth: 200 }}>
                <span style={{ fontSize: 20 }}>{i === 0 ? '🥇' : i === 1 ? '🥈' : '🥉'}</span>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{r.candidateName}</div>
                  <div style={{ color: '#10b981', fontWeight: 700 }}>{Math.round(r.atsScore)}% match</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* SEARCH AND FILTER */}
      <div style={{ display: 'flex', gap: 10, marginBottom: 16, flexWrap: 'wrap' }}>
        <input placeholder="Search by name..." value={search} onChange={e => setSearch(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleSearch()} style={{ flex: 1, minWidth: 200 }} />
        <button className="btn-primary" onClick={handleSearch}>Search</button>
        <button style={{ background: '#e5e7eb', borderRadius: 6, border: 'none', padding: '10px 16px', cursor: 'pointer' }} onClick={() => { setSearch(''); load(); }}>Reset</button>
        <select value={filter} onChange={e => setFilter(e.target.value)} style={{ padding: '10px', borderRadius: 6, border: '1px solid #ddd' }}>
          <option value="all">All Candidates</option>
          <option value="top">🟢 Strong (70%+)</option>
          <option value="mid">🟡 Average (40-69%)</option>
          <option value="low">🔴 Weak (below 40%)</option>
        </select>
      </div>

      {/* STATS ROW */}
      {resumes.length > 0 && (
        <div style={{ display: 'flex', gap: 12, marginBottom: 16 }}>
          {[
            { label: 'Total', val: resumes.length, color: '#4f46e5' },
            { label: '🟢 Strong', val: resumes.filter(r => r.atsScore >= 70).length, color: '#10b981' },
            { label: '🟡 Average', val: resumes.filter(r => r.atsScore >= 40 && r.atsScore < 70).length, color: '#f59e0b' },
            { label: '🔴 Weak', val: resumes.filter(r => r.atsScore < 40).length, color: '#ef4444' },
          ].map(s => (
            <div key={s.label} style={{ background: '#fff', borderRadius: 8, padding: '8px 16px', boxShadow: '0 1px 4px rgba(0,0,0,0.08)', textAlign: 'center' }}>
              <div style={{ fontWeight: 700, color: s.color, fontSize: 20 }}>{s.val}</div>
              <div style={{ fontSize: 12, color: '#666' }}>{s.label}</div>
            </div>
          ))}
        </div>
      )}

      {/* CANDIDATES LIST */}
      {filtered.length === 0 ? (
        <div className="card"><p style={{ color: '#999' }}>No resumes found.</p></div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {filtered.map((r, i) => (
            <div key={r.id} className="card" style={{ display: 'flex', gap: 16, alignItems: 'flex-start', borderLeft: `4px solid ${r.atsScore >= 70 ? '#10b981' : r.atsScore >= 40 ? '#f59e0b' : '#ef4444'}` }}>
              <div style={{ fontWeight: 700, fontSize: 16, color: '#aaa', width: 28, flexShrink: 0, paddingTop: 16 }}>#{i + 1}</div>
              <ScoreBadge score={Math.round(r.atsScore)} />
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 16 }}>{r.candidateName}</div>
                <div style={{ color: '#666', fontSize: 13 }}>{r.email} · {r.fileName}</div>
                <div style={{ marginTop: 8, fontSize: 13 }}>
                  <strong>Matched Skills: </strong>
                  {r.extractedSkills ? r.extractedSkills.split(',').map((s, i) => (
                    <span key={i} style={{ background: '#d1fae5', color: '#065f46', borderRadius: 10, padding: '2px 8px', fontSize: 12, marginRight: 4, marginTop: 4, display: 'inline-block' }}>{s.trim()}</span>
                  )) : <span style={{ color: '#999' }}>None detected</span>}
                </div>
              </div>
              <div style={{ flexShrink: 0, display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 6 }}>
                <span style={{ fontSize: 11, color: '#aaa' }}>{new Date(r.uploadedAt).toLocaleDateString()}</span>
                <button className="btn-danger" style={{ fontSize: 12, padding: '5px 10px' }} onClick={() => handleDelete(r.id)}>Delete</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
